#pragma once

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cuda_bf16.h>
#include <string>

#ifndef EPSILON
#define EPSILON 1e-6f
#endif

// Kernel configuration constants
constexpr int HIDDEN_SIZE = 512;
constexpr int THREADS_PER_BLOCK = 256;
constexpr int WARPS_PER_BLOCK = THREADS_PER_BLOCK / 32;
constexpr int THREADS_PER_WARP = 32;

/**
 * RMSNorm kernel declaration
 * 
 * @param hidden_states Input tensor [batch_size, hidden_size] in bfloat16
 * @param weight Weight tensor [hidden_size] in bfloat16
 * @param output Output tensor [batch_size, hidden_size] in bfloat16
 * @param batch_size Number of samples in batch
 * @param hidden_size Hidden dimension (fixed at 512)
 */
__global__ void rmsnorm_kernel(
    const __nv_bfloat16* __restrict__ hidden_states,
    const __nv_bfloat16* __restrict__ weight,
    __nv_bfloat16* __restrict__ output,
    int batch_size,
    int hidden_size
);

/**
 * Host function to launch RMSNorm kernel
 * 
 * @param hidden_states Input tensor data pointer
 * @param weight Weight tensor data pointer
 * @param output Output tensor data pointer
 * @param batch_size Number of samples in batch
 * @param hidden_size Hidden dimension
 * @param stream CUDA stream for async execution
 * @return cudaError_t Error code
 */
cudaError_t launch_rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    cudaStream_t stream = 0
);

#include "kernel.h"
#include <device_launch_parameters.h>
#include <cooperative_groups.h>

namespace cg = cooperative_groups;

/**
 * Warp-level reduction for sum
 * Optimized for A800 architecture
 */
__device__ __forceinline__ float warp_reduce_sum(float val) {
    float sum = val;
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        sum += __shfl_down_sync(0xffffffff, sum, offset);
    }
    return sum;
}

/**
 * Block-level reduction using shared memory
 */
__device__ __forceinline__ void block_reduce_sum(
    float* shared_sum,
    float val,
    int tid
) {
    // First level reduction in warp
    float warp_sum = warp_reduce_sum(val);

    // Store warp sums in shared memory
    if (tid % THREADS_PER_WARP == 0) {
        shared_sum[tid / THREADS_PER_WARP] = warp_sum;
    }
    __syncthreads();

    // Second level reduction for remaining warps
    if (tid < WARPS_PER_BLOCK) {
        float final_sum = warp_reduce_sum(shared_sum[tid]);
        if (tid == 0) {
            shared_sum[0] = final_sum;
        }
    }
}

/**
 * RMSNorm kernel optimized for A800 with hidden_size=512
 * 
 * Strategy:
 * - Each block processes one row (one sample in batch)
 * - 256 threads per block, 2 warps handle 512 elements
 * - Use shared memory for weight broadcast
 * - Two-pass approach: compute RMS, then normalize
 */
__global__ void rmsnorm_kernel(
    const __nv_bfloat16* __restrict__ hidden_states,
    const __nv_bfloat16* __restrict__ weight,
    __nv_bfloat16* __restrict__ output,
    int batch_size,
    int hidden_size
) {
    int row_id = blockIdx.x;
    if (row_id >= batch_size) return;

    int tid = threadIdx.x;

    // Shared memory for weight (512 elements * 2 bytes = 1KB)
    __shared__ __nv_bfloat16 shared_weight[HIDDEN_SIZE];

    // Shared memory for reduction
    __shared__ float shared_sum[WARPS_PER_BLOCK];

    // Load weight to shared memory (first thread of each warp)
    if (tid < HIDDEN_SIZE) {
        shared_weight[tid] = weight[tid];
    }
    __syncthreads();

    // Pointer to current row
    const __nv_bfloat16* row_ptr = hidden_states + row_id * hidden_size;
    __nv_bfloat16* out_ptr = output + row_id * hidden_size;

    // First pass: compute sum of squares
    float sum_sq = 0.0f;

    #pragma unroll 4
    for (int i = tid; i < HIDDEN_SIZE; i += THREADS_PER_BLOCK) {
        float x = __bfloat162float(row_ptr[i]);
        sum_sq += x * x;
    }

    // Block-level reduction for sum of squares
    block_reduce_sum(shared_sum, sum_sq, tid);
    __syncthreads();

    // Compute RMS and inverse RMS
    float rms = sqrtf(shared_sum[0] / HIDDEN_SIZE + EPSILON);
    float inv_rms = 1.0f / rms;

    // Second pass: normalize and scale
    #pragma unroll 4
    for (int i = tid; i < HIDDEN_SIZE; i += THREADS_PER_BLOCK) {
        float x = __bfloat162float(row_ptr[i]);
        float w = __bfloat162float(shared_weight[i]);
        float y = x * inv_rms * w;
        out_ptr[i] = __float2bfloat16(y);
    }
}

/**
 * Host function to launch RMSNorm kernel with optimal configuration
 */
cudaError_t launch_rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    cudaStream_t stream
) {
    // Validate hidden size
    if (hidden_size != HIDDEN_SIZE) {
        return cudaErrorInvalidValue;
    }

    // Configure kernel launch parameters
    dim3 grid(batch_size);
    dim3 block(THREADS_PER_BLOCK);

    // Launch kernel
    rmsnorm_kernel<<<grid, block, 0, stream>>>(
        hidden_states,
        weight,
        output,
        batch_size,
        hidden_size
    );

    // Check for launch errors
    cudaError_t err = cudaGetLastError();
    return err;
}

#include <torch/extension.h>
#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <string>
#include <iostream>
#include "kernel.h"

/**
 * Validate tensor properties for RMSNorm
 */
void validate_tensors(
    const torch::Tensor& hidden_states,
    const torch::Tensor& weight
) {
    // Check device
    TORCH_CHECK(hidden_states.device().is_cuda(), "hidden_states must be on CUDA device");
    TORCH_CHECK(weight.device().is_cuda(), "weight must be on CUDA device");

    // Check dtype
    TORCH_CHECK(hidden_states.dtype() == torch::kBFloat16, 
                "hidden_states must be bfloat16");
    TORCH_CHECK(weight.dtype() == torch::kBFloat16, 
                "weight must be bfloat16");

    // Check shapes
    TORCH_CHECK(hidden_states.dim() == 2, 
                "hidden_states must be 2D tensor [batch_size, hidden_size]");
    TORCH_CHECK(weight.dim() == 1, 
                "weight must be 1D tensor [hidden_size]");

    int hidden_size = hidden_states.size(1);
    TORCH_CHECK(hidden_size == HIDDEN_SIZE, 
                "hidden_size must be " + std::to_string(HIDDEN_SIZE) + 
                ", got " + std::to_string(hidden_size));

    TORCH_CHECK(weight.size(0) == hidden_size, 
                "weight size must match hidden_size");
}

/**
 * Main run function for PyTorch integration
 * 
 * @param hidden_states Input tensor [batch_size, hidden_size]
 * @param weight Weight tensor [hidden_size]
 * @return Output tensor [batch_size, hidden_size]
 */
torch::Tensor run(
    const torch::Tensor& hidden_states,
    const torch::Tensor& weight
) {
    // Validate inputs
    validate_tensors(hidden_states, weight);

    // Extract dimensions
    int batch_size = hidden_states.size(0);
    int hidden_size = hidden_states.size(1);

    // Create output tensor
    torch::Tensor output = torch::empty_like(hidden_states);

    // Get raw pointers
    const __nv_bfloat16* hidden_states_ptr = 
        hidden_states.data_ptr<__nv_bfloat16>();
    const __nv_bfloat16* weight_ptr = 
        weight.data_ptr<__nv_bfloat16>();
    __nv_bfloat16* output_ptr = 
        output.data_ptr<__nv_bfloat16>();

    // Get current CUDA stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel
    cudaError_t err = launch_rmsnorm_kernel(
        hidden_states_ptr,
        weight_ptr,
        output_ptr,
        batch_size,
        hidden_size,
        stream
    );

    if (err != cudaSuccess) {
        TORCH_CHECK(false, "RMSNorm kernel launch failed: " + 
                    std::string(cudaGetErrorString(err)));
    }

    // Check for kernel execution errors
    err = cudaGetLastError();
    if (err != cudaSuccess) {
        TORCH_CHECK(false, "RMSNorm kernel execution failed: " + 
                    std::string(cudaGetErrorString(err)));
    }

    return output;
}

/**
 * Run function with kwargs support
 */
torch::Tensor run_with_kwargs(
    c10::Dict<std::string, torch::Tensor>& kwargs
) {
    // Extract arguments from kwargs using at method (correct for c10::Dict)
    TORCH_CHECK(kwargs.contains("hidden_states"), 
                "Missing required argument: hidden_states");
    TORCH_CHECK(kwargs.contains("weight"), 
                "Missing required argument: weight");

    torch::Tensor hidden_states = kwargs.at("hidden_states");
    torch::Tensor weight = kwargs.at("weight");

    return run(hidden_states, weight);
}

/**
 * PyBind11 module definition
 */
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Execute RMSNorm kernel on A800 GPU");
    m.def("run_kwargs", &run_with_kwargs, "Execute RMSNorm kernel with kwargs");

    // Add module version
    m.attr("__version__") = "1.0.0";
}
